#include <stdio.h>
#include <stdlib.h>

void allocateMatrix(int rows, int cols) {
    int totalSize = rows * cols * sizeof(double);
    double* matrix = (double*)malloc(totalSize);

    if (matrix == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return;
    }

    // Example usage: Initialize the matrix with some values
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            matrix[i * cols + j] = 0.0; // Initialize to zero or any other value
        }
    }

    // Example usage: Print the matrix
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            printf("%f ", matrix[i * cols + j]);
        }
        printf("\n");
    }

    free(matrix);
}

int main() {
    int rows, cols;
    printf("Enter number of rows: ");
    scanf("%d", &rows);
    printf("Enter number of columns: ");
    scanf("%d", &cols);

    allocateMatrix(rows, cols);

    return 0;
}